--
-- Triggers `tblapplication4loan`
--
DELIMITER $$
CREATE TRIGGER `after_loan_approval` AFTER UPDATE ON `tblapplication4loan` FOR EACH ROW BEGIN
    DECLARE i INT DEFAULT 1;
    
    IF NEW.acc_status = 2 AND (OLD.acc_status IS NULL OR OLD.acc_status = 1) THEN

        WHILE i <= NEW.loantenure DO
                loanappid, 
                member_id, 
                installment_no, 
                emi_amount, 
                due_date,
                payment_status
            ) 
            VALUES (
                NEW.loanappid, 
                NEW.creator_id,
                i, 
                NEW.monthemi, 
                DATE_ADD(CURDATE(), INTERVAL i MONTH),
                'Unpaid'
            );
            SET i = i + 1;
        END WHILE;
        
    END IF;
END
$$
DELIMITER ;

